#include <stdio.h>
#include <stdlib.h>

#define MAX 100

typedef struct {
  int adj[MAX][MAX];
  int vertices;
} Graph;

void initGraph(Graph* g, int vertices) {
  g->vertices = vertices;
  for (int i = 0; i < vertices; i++)
    for (int j = 0; j < vertices; j++)
      g->adj[i][j] = 0;
}

void addEdge(Graph* g, int u, int v) {
  g->adj[u][v] = 1;
}

void topologicalSortUtil(Graph* g, int v, int visited[], int stack[], int* stackIndex) {
  visited[v] = 1;
  for (int i = 0; i < g->vertices; i++) {
    if (g->adj[v][i] && !visited[i])
      topologicalSortUtil(g, i, visited, stack, stackIndex);
  }
  stack[(*stackIndex)++] = v;
}

void topologicalSort(Graph* g) {
  int visited[MAX] = {0};
  int stack[MAX];
  int stackIndex = 0;
  for (int i = 0; i < g->vertices; i++) {
    if (!visited[i])
      topologicalSortUtil(g, i, visited, stack, &stackIndex);
  }
  printf("Topological Sort:\n");
  for (int i = stackIndex - 1; i >= 0; i--)
    printf("%d ", stack[i]);
  printf("\n");
}

int main() {
  Graph g;
  initGraph(&g, 6);
  addEdge(&g, 5, 2); addEdge(&g, 5, 0); addEdge(&g, 4, 0);
  addEdge(&g, 4, 1); addEdge(&g, 2, 3); addEdge(&g, 3, 1);
  topologicalSort(&g);
  return 0;
}
// Output: 
// Topological Sort:
// 5 4 2 3 1 0

